// Assemble the prompt context for Claude Sonnet
const interview = $('Has Interviews?').first().json;
const companyData = $('Get Company Research').first().json;
const salaryData = $('Get Salary Research').first().json;

const companyResearch = companyData.research_data 
  ? `COMPANY RESEARCH:\n${JSON.stringify(companyData.research_data, null, 2)}\nResearch completeness: ${companyData.research_completeness || 'none'}`
  : 'COMPANY RESEARCH: No cached research available. Use publicly known information about this company.';

const salaryInfo = salaryData.salary_min
  ? `SALARY INTELLIGENCE:\n- Range: ${salaryData.salary_currency || 'GBP'} ${salaryData.salary_min} - ${salaryData.salary_max}\n- Median: ${salaryData.salary_currency || 'GBP'} ${salaryData.salary_median}\n- Typical bonus: ${salaryData.typical_bonus_percentage || 'N/A'}%\n- Typical pension: ${salaryData.typical_pension_percentage || 'N/A'}%\n- Benefits notes: ${salaryData.benefits_notes || 'N/A'}`
  : 'SALARY INTELLIGENCE: No cached salary data. Provide general UK market guidance for this role level.';

const interviewerInfo = interview.interviewer_names && interview.interviewer_names.length > 0
  ? `INTERVIEWERS: ${interview.interviewer_names.join(', ')}${interview.interviewer_titles ? ' (' + interview.interviewer_titles.join(', ') + ')' : ''}`
  : 'INTERVIEWERS: Not specified';

const prompt = `Generate a comprehensive interview preparation brief for the following interview.

CANDIDATE PROFILE:
- PhD + MBA professional with 18 years of HR/L&D experience
- Currently targeting UK L&D Manager to Head of L&D roles (corporate) and Lecturer/Senior Lecturer positions (academic)
- Target salary: GBP 70,000-80,000 (corporate) or appropriate academic grade
- Location: Maidenhead, UK
- Key strengths: stakeholder management, programme design & delivery, ROI measurement, change management, digital learning strategy
- 90% callback-to-offer rate

INTERVIEW DETAILS:
- Company: ${interview.company_name}
- Role: ${interview.role_title}
- Track: ${interview.interview_track}
- Format: ${interview.interview_format}
- Stage: ${interview.interview_stage || 'Not specified'}
- Date: ${interview.interview_date}
- Time: ${interview.interview_start_time || 'TBC'} - ${interview.interview_end_time || 'TBC'}
- Duration: ${interview.interview_duration_minutes || 60} minutes
- Location type: ${interview.location_type || 'Not specified'}
- Physical address: ${interview.physical_address || 'N/A'}
- Video platform: ${interview.video_platform || 'N/A'}
${interviewerInfo}
- What to prepare: ${interview.what_to_prepare || 'Not specified'}
- What to bring: ${interview.what_to_bring || 'Not specified'}
- Dress code: ${interview.dress_code || 'Not specified'}
- Additional instructions: ${interview.additional_instructions || 'None'}

${companyResearch}

${salaryInfo}

Please generate a structured preparation brief with these sections:

1. **COMPANY OVERVIEW** - Key facts, culture, recent news, strategic direction
2. **ROLE ANALYSIS** - Key requirements, likely priorities, challenges the hiring manager faces
3. **YOUR FIT** - How the candidate's experience maps to role requirements, key selling points
4. **LIKELY QUESTIONS** (${interview.interview_track === 'academic' ? 'academic format: teaching philosophy, research alignment, REF impact' : 'UK competency-based STAR format'}) - 8-10 questions with suggested STAR response angles
5. **QUESTIONS TO ASK** - 5-7 intelligent questions that demonstrate understanding and genuine interest
6. **SALARY & NEGOTIATION INTELLIGENCE** - Market rates, negotiation leverage points, benefits to discuss
7. **LOGISTICS & FORMAT TIPS** - Format-specific advice, technology checks, timing
8. **FINAL CHECKLIST** - Day-before and day-of checklist items

Be specific to this company and role. Avoid generic advice. Reference UK employment practices and norms.`;

return {
  interview_id: interview.interview_id,
  company_name: interview.company_name,
  role_title: interview.role_title,
  interview_date: interview.interview_date,
  interview_track: interview.interview_track,
  prompt: prompt
};

