parameters.jsCode:
const input = $('Assemble Prompt').first().json;
const response = $('Claude Sonnet: Generate Brief').first().json;

// Check for API error
if (response.error || !response.content || !response.content[0]) {
  return {
    interview_id: input.interview_id,
    company_name: input.company_name,
    role_title: input.role_title,
    success: false,
    error: response.error?.message || 'No content in Claude response'
  };
}

const briefText = response.content[0].text;
const usage = response.usage || {};

// Extract sections using regex
const sections = {};
const sectionPatterns = [
  { key: 'company_overview', pattern: /\*\*(?:1\.\s*)?COMPANY OVERVIEW\*\*([\s\S]*?)(?=\n\*\*(?:2\.|ROLE)|$)/i },
  { key: 'role_analysis', pattern: /\*\*(?:2\.\s*)?ROLE ANALYSIS\*\*([\s\S]*?)(?=\n\*\*(?:3\.|YOUR)|$)/i },
  { key: 'candidate_fit', pattern: /\*\*(?:3\.\s*)?YOUR FIT\*\*([\s\S]*?)(?=\n\*\*(?:4\.|LIKELY)|$)/i },
  { key: 'likely_questions', pattern: /\*\*(?:4\.\s*)?LIKELY QUESTIONS\*\*([\s\S]*?)(?=\n\*\*(?:5\.|QUESTIONS TO)|$)/i },
  { key: 'questions_to_ask', pattern: /\*\*(?:5\.\s*)?QUESTIONS TO ASK\*\*([\s\S]*?)(?=\n\*\*(?:6\.|SALARY)|$)/i },
  { key: 'salary_intelligence', pattern: /\*\*(?:6\.\s*)?SALARY.*?INTELLIGENCE\*\*([\s\S]*?)(?=\n\*\*(?:7\.|LOGISTICS)|$)/i },
  { key: 'logistics_and_format', pattern: /\*\*(?:7\.\s*)?LOGISTICS.*?\*\*([\s\S]*?)(?=\n\*\*(?:8\.|FINAL)|$)/i },
  { key: 'final_checklist', pattern: /\*\*(?:8\.\s*)?FINAL CHECKLIST\*\*([\s\S]*?)$/i }
];

for (const sp of sectionPatterns) {
  const match = briefText.match(sp.pattern);
  sections[sp.key] = match ? match[1].trim() : null;
}

// Calculate cost (Sonnet pricing: $3/MTok input, $15/MTok output)
const inputTokens = usage.input_tokens || 0;
const outputTokens = usage.output_tokens || 0;
const costUsd = (inputTokens * 3 / 1000000) + (outputTokens * 15 / 1000000);

return {
  interview_id: input.interview_id,
  company_name: input.company_name,
  role_title: input.role_title,
  interview_date: input.interview_date,
  interview_track: input.interview_track,
  full_brief_text: briefText,
  sections: sections,
  model_used: 'claude-sonnet-4-20250514',
  prompt_tokens: inputTokens,
  completion_tokens: outputTokens,
  generation_cost_usd: costUsd,
  success: true
};

